import { useEffect, useState } from "react";
import { foods } from "../data/foods";
import FoodCard from "../components/FoodCard";
import { motion } from "framer-motion";
console.log("HOME PAGE LOADED");
export default function Home() {
  const [backendMessage, setBackendMessage] = useState("Loading...");

  useEffect(() => {
    fetch("http://localhost:8080/api/test")
      .then((res) => res.text())
      .then((data) => {
        console.log("FROM BACKEND:", data);
        setBackendMessage(data);
      })
      .catch((err) => {
        console.error("ERROR:", err);
        setBackendMessage("Backend NOT connected");
      });
  }, []);

  return (
    <motion.main
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="p-6"
    >

      {/* 🔴 TEST MESSAGE (to confirm file is loading) */}
      <h1 style={{ color: "red", textAlign: "center" }}>
        TEST MESSAGE
      </h1>

      {/* 🔥 Backend status */}
      <div className="max-w-6xl mx-auto mb-6 p-4 rounded-xl bg-black text-white text-center">
        <p className="font-bold">Backend Status:</p>
        <p>{backendMessage}</p>
      </div>

      <section className="max-w-6xl mx-auto mb-8 text-center">
        <h1 className="text-4xl font-extrabold text-slate-900">
          Delicious food, delivered fast
        </h1>
        <p className="mt-3 text-gray-600">
          Browse our menu and add your favorites to the cart.
        </p>
      </section>

      <section className="max-w-6xl mx-auto">
        <h2 className="text-2xl font-bold mb-4">Menu</h2>

        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {foods.map((food) => (
            <FoodCard key={food.id} food={food} />
          ))}
        </div>
      </section>
    </motion.main>
  );
}
